sql:
SELECT COUNT(*) 
FROM court_cases 
WHERE case_type_id = (SELECT case_type_id FROM case_types WHERE case_type = 'Jury Trial');

SELECT COUNT(*)
FROM court_cases
WHERE date LIKE '2023-%' AND case_status = 'Closed';

SELECT case_id
FROM hearings
WHERE hearing_id = 1;

SELECT 
    (SELECT COUNT(DISTINCT courtroom_location) FROM courtrooms) AS total_courtroom_locations,
    (SELECT judge_name FROM judges WHERE judge_id = (SELECT judge_id FROM court_cases WHERE case_number = '17-cr-0135')) AS assigned_judge_name;

SELECT judge_name 
FROM judges 
WHERE judge_id = (SELECT judge_id FROM court_cases WHERE case_id = 1);

SELECT case_number
FROM court_cases
WHERE case_id = 2;

SELECT COUNT(*) AS case_count
FROM court_cases
WHERE judge_id = (SELECT judge_id FROM judges WHERE judge_name = 'Judge Mary Johnson');
